public record Point(int x, int y) {
    public Point {
        if (x < 0) throw new IllegalArgumentException();
    }
}
// In main:
Point p = new Point(3, 4);
System.out.println(p.x() + " " + p.y());

interface Greet {
    default String hello() { return "Hello"; }
}
interface Farewell {
    default String hello() { return "Bye"; }
}
class MyClass implements Greet, Farewell {
    public String hello() { return Greet.super.hello(); }
}
// In main:
System.out.println(new MyClass().hello());

abstract class Animal {
    String name;
    Animal(String name) { this.name = name; }
    abstract String sound();
    String describe() { return name + " says " + sound(); }
}
class Dog extends Animal {
    Dog(String name) { super(name); }
    String sound() { return "woof"; }
}
// In main:
Animal a = new Dog("Rex");
System.out.println(a.describe());

class Parent {
    void print(int x) { System.out.println("Parent int"); }
}
class Child extends Parent {
    void print(int x) { System.out.println("Child int"); } // (1)
    void print(double x) { System.out.println("Child double"); } // (2)
}

class Base {
    Base() { print(); }
    void print() { System.out.println("Base"); }
}
class Derived extends Base {
    int value = 10;
    Derived() { super(); }
    void print() { System.out.println("Derived: " + value); }
}
// In main:
new Derived();

public class Outer {
    private int x = 10;
    class Inner {
        private int x = 20;
        void print() {
            int x = 30;
            System.out.println(x);           // (1)
            System.out.println(this.x);      // (2)
            System.out.println(Outer.this.x);// (3)
        }
    }
    public static void main(String[] args) {
        new Outer().new Inner().print();
    }
}

public class Outer {
    static int value = 5;
    static class Nested {
        void show() { System.out.println("Value: " + value); }
    }
    public static void main(String[] args) {
        Nested n = new Nested();
        n.show();
    }
}
